record.field:
for record in records:
    if record.amount_total < 10000:
        category = 'low'
    elif 10000 <= record.amount_total <= 50000:
        category = 'medium'
    else:
        category = 'high'

    record.write({'order_value_category': category})

    labels = {'low': 'Low', 'medium': 'Medium', 'high': 'High'}
    record.message_post(
        body="Order Value Category set to: %s (Total: $%s)" % (labels[category], record.amount_total),
        subtype_xmlid='mail.mt_note',
    )
